CREATE TABLE users (id UUID PRIMARY KEY, full_name VARCHAR(150) NOT NULL, email VARCHAR(180) NOT NULL UNIQUE, phone_number VARCHAR(30) NOT NULL, password_hash TEXT NOT NULL, is_kyc_verified BOOLEAN NOT NULL, avatar_url TEXT NULL, created_on_utc TIMESTAMPTZ NOT NULL, modified_on_utc TIMESTAMPTZ NULL);
CREATE TABLE user_roles (id UUID PRIMARY KEY, user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, role VARCHAR(50) NOT NULL);
CREATE TABLE properties (id UUID PRIMARY KEY, owner_id UUID NOT NULL REFERENCES users(id), title VARCHAR(180) NOT NULL, description TEXT NOT NULL, property_type VARCHAR(50) NOT NULL, price_amount NUMERIC(18,2) NOT NULL, price_currency VARCHAR(3) NOT NULL, city VARCHAR(100) NOT NULL, area VARCHAR(100) NOT NULL, latitude NUMERIC(10,7) NOT NULL, longitude NUMERIC(10,7) NOT NULL, bhk INT NOT NULL, status VARCHAR(50) NOT NULL, created_on_utc TIMESTAMPTZ NOT NULL, modified_on_utc TIMESTAMPTZ NULL);
CREATE TABLE listings (id UUID PRIMARY KEY, property_id UUID NOT NULL REFERENCES properties(id) ON DELETE CASCADE, slug VARCHAR(220) NOT NULL UNIQUE, listing_type VARCHAR(30) NOT NULL, is_featured BOOLEAN NOT NULL, is_approved BOOLEAN NOT NULL, published_on_utc TIMESTAMPTZ NOT NULL, view_count INT NOT NULL);
CREATE TABLE subscription_plans (id UUID PRIMARY KEY, name VARCHAR(100) NOT NULL, plan_type VARCHAR(30) NOT NULL, price NUMERIC(18,2) NOT NULL, currency VARCHAR(3) NOT NULL, listing_quota INT NOT NULL, allows_featured_listings BOOLEAN NOT NULL, priority_visibility BOOLEAN NOT NULL, duration_in_days INT NOT NULL, is_active BOOLEAN NOT NULL);
CREATE TABLE user_subscriptions (id UUID PRIMARY KEY, user_id UUID NOT NULL REFERENCES users(id), plan_id UUID NOT NULL REFERENCES subscription_plans(id), status VARCHAR(30) NOT NULL, starts_on_utc TIMESTAMPTZ NOT NULL, ends_on_utc TIMESTAMPTZ NOT NULL, listings_consumed INT NOT NULL);
